import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import styled from 'styled-components';
import ThemeToggle from './ThemeToggle';
import { useTheme } from '../context/ThemeContext';

const Nav = styled.nav`
  position: fixed;
  width: 100%;
  z-index: 1000;
  background: ${props => props.theme.navBackground};
  backdrop-filter: blur(10px);
  box-shadow: ${props => props.theme.shadow};
`;

const Container = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 10%;
`;

const Logo = styled.span`
  font-family: 'Orbitron', sans-serif;
  font-size: 1.5rem;
  color: ${props => props.theme.primary};
`;

const NavLinks = styled.ul`
  display: flex;
  gap: 2rem;
  list-style: none;

  @media (max-width: 768px) {
    display: none;
  }
`;

const NavLink = styled(Link)`
  color: ${props => props.theme.text};
  text-decoration: none;
  font-weight: 500;
  transition: color 0.3s ease;

  &:hover {
    color: ${props => props.theme.hoverColor};
  }
`;

const JoinButton = styled.button`
  background: none;
  border: none;
  margin-left: auto;

  a {
    color: ${props => props.theme.primary};
    text-decoration: none;
    padding: 8px 20px;
    border: 2px solid ${props => props.theme.primary};
    border-radius: 25px;
    transition: all 0.3s ease;

    &:hover {
      background: ${props => props.theme.primary};
      color: ${props => props.theme.background};
    }
  }
`;

const Navbar = () => {
  const { theme, isDarkTheme } = useTheme();
  
  return (
    <Nav theme={theme}>
      <Container>
        <img src={require('../assets/symbol.png')} alt="logo" />
        <NavLinks theme={theme}>
          <li><NavLink to="/team" theme={theme}>TEAM</NavLink></li>
          <li><NavLink to="/gallery" theme={theme}>GALLERY</NavLink></li>
        </NavLinks>
        <Logo theme={theme}><NavLink to="/events" theme={theme}>HOME</NavLink></Logo>
        <NavLinks theme={theme}>
          <li><NavLink to="/events" theme={theme}>EVENT</NavLink></li>
          <li><NavLink to="#footer" theme={theme}>CONTACT</NavLink></li>
        </NavLinks>        
        <JoinButton theme={theme}>
          <a href="https://github.com/optimusorgz" target="_blank" rel="noopener noreferrer">
            Join us
          </a>
        </JoinButton>
        <ThemeToggle />
      </Container>
    </Nav>
  );
};

export default Navbar;
